export function aStarGridShortestPath(
	grid: number[][],
	start: readonly [number, number],
	end: readonly [number, number]
): number | null {
	const rows = grid.length;
	if (rows === 0) return null;
	const cols = grid[0]?.length ?? 0;
	if (cols === 0) return null;

	const [sr, sc] = start;
	const [er, ec] = end;

	const inBounds = (r: number, c: number) => r >= 0 && r < rows && c >= 0 && c < cols;

	if (!inBounds(sr, sc) || !inBounds(er, ec)) return null;
	if (grid[sr][sc] !== 0 || grid[er][ec] !== 0) return null;
	if (sr === er && sc === ec) return 0;

	const manhattan = (r: number, c: number) => Math.abs(r - er) + Math.abs(c - ec);

	type Node = { r: number; c: number; g: number; f: number };

	class MinHeap {
		private data: Node[] = [];

		get size(): number {
			return this.data.length;
		}

		push(item: Node): void {
			this.data.push(item);
			this.bubbleUp(this.data.length - 1);
		}

		pop(): Node | undefined {
			if (this.data.length === 0) return undefined;
			const top = this.data[0];
			const last = this.data.pop()!;
			if (this.data.length > 0) {
				this.data[0] = last;
				this.bubbleDown(0);
			}
			return top;
		}

		private bubbleUp(index: number): void {
			while (index > 0) {
				const parent = (index - 1) >> 1;
				if (this.compare(this.data[index], this.data[parent]) >= 0) break;
				[this.data[index], this.data[parent]] = [this.data[parent], this.data[index]];
				index = parent;
			}
		}

		private bubbleDown(index: number): void {
			const n = this.data.length;
			for (;;) {
				let smallest = index;
				const left = index * 2 + 1;
				const right = index * 2 + 2;

				if (left < n && this.compare(this.data[left], this.data[smallest]) < 0) smallest = left;
				if (right < n && this.compare(this.data[right], this.data[smallest]) < 0) smallest = right;

				if (smallest === index) break;
				[this.data[index], this.data[smallest]] = [this.data[smallest], this.data[index]];
				index = smallest;
			}
		}

		private compare(a: Node, b: Node): number {
			if (a.f !== b.f) return a.f - b.f;
			return a.g - b.g;
		}
	}

	const gScore: number[][] = Array.from({ length: rows }, () => Array(cols).fill(Infinity));
	gScore[sr][sc] = 0;

	const open = new MinHeap();
	open.push({ r: sr, c: sc, g: 0, f: manhattan(sr, sc) });

	const dirs = [
		[1, 0],
		[-1, 0],
		[0, 1],
		[0, -1],
	] as const;

	while (open.size > 0) {
		const current = open.pop()!;
		const { r, c, g } = current;

		if (g !== gScore[r][c]) continue;

		if (r === er && c === ec) return g;

		for (const [dr, dc] of dirs) {
			const nr = r + dr;
			const nc = c + dc;

			if (!inBounds(nr, nc)) continue;
			if (grid[nr][nc] !== 0) continue;

			const ng = g + 1;
			if (ng < gScore[nr][nc]) {
				gScore[nr][nc] = ng;
				open.push({ r: nr, c: nc, g: ng, f: ng + manhattan(nr, nc) });
			}
		}
	}

	return null;
}

