const __legacySolution = (function binarySearchBoundary(values: number[], target: number): number {
		let low = 0;
		let high = values.length - 1;
		let answer = -1;

		while (low <= high) {
			const middle = low + Math.floor((high - low) / 2);
			const current = values.at(middle);
			if (typeof current !== 'number') {
				break;
			}

			if (current >= target) {
				if (current === target) {
					answer = middle;
				}
				high = middle - 1;
			} else {
				low = middle + 1;
			}
		}

		return answer;
	});
export const binarySearchBoundary = __legacySolution;

export function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
	const findBound = (isFirst: boolean): number => {
		let left = 0;
		let right = values.length - 1;
		let bound = -1;

		while (left <= right) {
			const mid = left + Math.floor((right - left) / 2);

			if (values[mid] === target) {
				bound = mid;
				if (isFirst) {
					right = mid - 1;
				} else {
					left = mid + 1;
				}
			} else if (values[mid] < target) {
				left = mid + 1;
			} else {
				right = mid - 1;
			}
		}

		return bound;
	};

	const first = findBound(true);
	if (first === -1) return [-1, -1];

	const last = findBound(false);
	return [first, last];
}

