				counts.set(char, (counts.get(char) ?? 0) + 1);
			}

			return [...counts.entries()]
				.sort((left, right) => left[0].localeCompare(right[0]))
				.map(([char, count]) => `${char}:${count}`)
				.join('|');
		};

