			case 'push': {
				if (value === undefined) {
					result.push(null);
					break;
				}
				stack.push(value);
				if (minStackValues.length === 0 || value <= minStackValues[minStackValues.length - 1]) {
					minStackValues.push(value);
				}
				result.push(null);
				break;
			}
			case 'pop': {
				if (stack.length === 0) {
					result.push(null);
					break;
				}
				const popped = stack.pop() as number;
				if (popped === minStackValues[minStackValues.length - 1]) {
					minStackValues.pop();
