export function toyRsaBigint(
	p: bigint,
	q: bigint,
	e: bigint,
	message: bigint
): {
	publicKey: { n: bigint; e: bigint };
	privateKey: { n: bigint; d: bigint };
	cipher: bigint;
	decrypted: bigint;
} {
	const n = p * q;
	const phi = (p - 1n) * (q - 1n);

	const mod = (a: bigint, m: bigint): bigint => {
		const r = a % m;
		return r >= 0n ? r : r + m;
	};

	const gcd = (a: bigint, b: bigint): bigint => {
		let x = a < 0n ? -a : a;
		let y = b < 0n ? -b : b;
		while (y !== 0n) {
			const t = x % y;
			x = y;
			y = t;
		}
		return x;
	};

	const extendedGcd = (a: bigint, b: bigint): { g: bigint; x: bigint; y: bigint } => {
		let oldR = a;
		let r = b;
		let oldS = 1n;
		let s = 0n;
		let oldT = 0n;
		let t = 1n;

		while (r !== 0n) {
			const qv = oldR / r;
			[oldR, r] = [r, oldR - qv * r];
			[oldS, s] = [s, oldS - qv * s];
			[oldT, t] = [t, oldT - qv * t];
		}

		return { g: oldR, x: oldS, y: oldT };
	};

	const modInverse = (a: bigint, m: bigint): bigint => {
		const { g, x } = extendedGcd(a, m);
		if (g !== 1n && g !== -1n) {
			throw new Error('e and phi(n) must be coprime');
		}
		return mod(x, m);
	};

	const modPow = (base: bigint, exp: bigint, m: bigint): bigint => {
		if (m === 1n) return 0n;
		let result = 1n;
		let b = mod(base, m);
		let eexp = exp;
		while (eexp > 0n) {
			if ((eexp & 1n) === 1n) result = (result * b) % m;
			b = (b * b) % m;
			eexp >>= 1n;
		}
		return result;
	};

	if (p <= 1n || q <= 1n) throw new Error('p and q must be > 1');
	if (e <= 1n) throw new Error('e must be > 1');
	if (message < 0n || message >= n) throw new Error('message must satisfy 0 <= message < n');
	if (gcd(e, phi) !== 1n) throw new Error('e and phi(n) must be coprime');

	const d = modInverse(e, phi);
	const cipher = modPow(message, e, n);
	const decrypted = modPow(cipher, d, n);

	return {
		publicKey: { n, e },
		privateKey: { n, d },
		cipher,
		decrypted,
	};
}

