export function unionFindConnectedComponentsOnline(
	n: number,
	operations: readonly (readonly [number, number])[],
): number[] {
	const parent: number[] = Array.from({ length: n }, (_, i) => i);
	const size: number[] = Array(n).fill(1);
	let components = n;
	const result: number[] = [];

	const find = (x: number): number => {
		let root = x;
		while (parent[root] !== root) root = parent[root];
		while (parent[x] !== x) {
			const next = parent[x];
			parent[x] = root;
			x = next;
		}
		return root;
	};

	for (const [a, b] of operations) {
		const ra = find(a);
		const rb = find(b);
		if (ra !== rb) {
			if (size[ra] < size[rb]) {
				parent[ra] = rb;
				size[rb] += size[ra];
			} else {
				parent[rb] = ra;
				size[ra] += size[rb];
			}
			components--;
		}
		result.push(components);
	}

	return result;
}

