:root {
	--color-bg: #f7f8fa;
	--color-surface: #ffffff;
	--color-text-primary: #0f172a;
	--color-text-secondary: #475569;
	--color-accent: #0a7d57;
	--color-border: #d6dce4;
	--shadow-elevated: 0 8px 24px rgba(15, 23, 42, 0.08);
	--focus-ring: 0 0 0 3px color-mix(in srgb, var(--color-accent) 35%, transparent);
	background-color: var(--color-bg);
	color: var(--color-text-primary);
	transition: background-color 180ms ease, color 180ms ease;
	color-scheme: light;
}

@media (prefers-color-scheme: dark) {
	:root {
		--color-bg: #0b1020;
		--color-surface: #121a2d;
		--color-text-primary: #e7edf7;
		--color-text-secondary: #a8b4c8;
		--color-accent: #58d9a3;
		--color-border: #2d3a55;
		--shadow-elevated: 0 10px 28px rgba(0, 0, 0, 0.35);
		--focus-ring: 0 0 0 3px color-mix(in srgb, var(--color-accent) 45%, transparent);
		color-scheme: dark;
	}
}

[data-theme='dark'] {
	--color-bg: #0b1020;
	--color-surface: #121a2d;
	--color-text-primary: #e7edf7;
	--color-text-secondary: #a8b4c8;
	--color-accent: #58d9a3;
	--color-border: #2d3a55;
	--shadow-elevated: 0 10px 28px rgba(0, 0, 0, 0.35);
	--focus-ring: 0 0 0 3px color-mix(in srgb, var(--color-accent) 45%, transparent);
	color-scheme: dark;
}

[data-theme='light'] {
	color-scheme: light;
}

*,
*::before,
*::after {
	box-sizing: border-box;
	transition:
		background-color 180ms ease,
		color 180ms ease,
		border-color 180ms ease,
		box-shadow 180ms ease;
}

html,
body {
	min-height: 100%;
}

body {
	margin: 0;
	background-color: var(--color-bg);
	color: var(--color-text-primary);
	font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
	line-height: 1.5;
}

.theme-toggle {
	display: inline-flex;
	align-items: center;
	gap: 0.5rem;
	padding: 0.5rem 0.75rem;
	border: 1px solid var(--color-border);
	border-radius: 999px;
	background: var(--color-surface);
	color: var(--color-text-primary);
	box-shadow: var(--shadow-elevated);
	font: inherit;
	cursor: pointer;
	-webkit-tap-highlight-color: transparent;
}

.theme-toggle::before {
	content: '◐';
	font-size: 0.95em;
	color: var(--color-text-secondary);
}

.theme-toggle::after {
	content: 'Light';
	font-weight: 600;
	color: var(--color-accent);
}

.theme-toggle:hover {
	border-color: color-mix(in srgb, var(--color-accent) 45%, var(--color-border));
}

.theme-toggle:focus-visible {
	outline: none;
	box-shadow: var(--shadow-elevated), var(--focus-ring);
}

@media (prefers-color-scheme: dark) {
	:root:not([data-theme='light']) .theme-toggle::after {
		content: 'Dark';
	}
}

[data-theme='dark'] .theme-toggle::after {
	content: 'Dark';
}

[data-theme='light'] .theme-toggle::after {
	content: 'Light';
}

@media (prefers-reduced-motion: reduce) {
	*,
	*::before,
	*::after {
		transition: none !important;
	}
}

