export function kLargestElementsInStream(stream: number[], k: number): number[][] {
	const result: number[][] = [];

	if (k <= 0) {
		for (let i = 0; i < stream.length; i++) {
			result.push([]);
		}
		return result;
	}

	const top: number[] = [];

	for (const value of stream) {
		let inserted = false;
		for (let i = 0; i < top.length; i++) {
			if (value > top[i]) {
				top.splice(i, 0, value);
				inserted = true;
				break;
			}
		}
		if (!inserted) {
			top.push(value);
		}

		if (top.length > k) {
			top.pop();
		}

		result.push([...top]);
	}

	return result;
}

