export class LRUCache {
	#capacity;
	#map = new Map();

	constructor(capacity) {
		if (capacity <= 0) {
			throw new RangeError('capacity must be > 0');
		}
		this.#capacity = capacity;
	}

	get(key) {
		if (!this.#map.has(key)) {
			return undefined;
		}
		const value = this.#map.get(key);
		this.#map.delete(key);
		this.#map.set(key, value);
		return value;
	}

	set(key, value) {
		if (this.#map.has(key)) {
			this.#map.delete(key);
		} else if (this.#map.size >= this.#capacity) {
