export function lruCache(
	capacity: number,
	operations: readonly (readonly ['get' | 'put', number, number?])[]
): (number | null)[] {
	if (!Number.isInteger(capacity) || capacity <= 0) {
		throw new Error('Invalid capacity');
	}

	const cache = new Map<number, number>();
	const results: (number | null)[] = [];

	for (const op of operations) {
		const [type, key, value] = op;

		if (type === 'get') {
			if (cache.has(key)) {
				const existing = cache.get(key)!;
				cache.delete(key);
				cache.set(key, existing);
				results.push(existing);
			} else {
				results.push(-1);
			}
		} else {
			if (value === undefined) {
				throw new Error('Put operation requires a value');
			}

			if (cache.has(key)) {
				cache.delete(key);
			} else if (cache.size >= capacity) {
				const lruKey = cache.keys().next().value as number;
				cache.delete(lruKey);
			}

			cache.set(key, value);
			results.push(null);
		}
	}

	return results;
}

