export function quickselectKthSmallest(values: number[], k: number): number {
	if (!Number.isInteger(k) || k < 1 || k > values.length) {
		throw new RangeError('k is out of bounds');
	}
	if (values.length === 0) {
		throw new RangeError('Cannot select from an empty array');
	}

	const arr = values.slice();
	let left = 0;
	let right = arr.length - 1;
	const target = k - 1;

	while (left <= right) {
		const pivotIndex = partition(arr, left, right);

		if (pivotIndex === target) {
			return arr[pivotIndex];
		}
		if (pivotIndex < target) {
			left = pivotIndex + 1;
		} else {
			right = pivotIndex - 1;
		}
	}

	throw new Error('Unexpected state');
}

