export type Row = Record<string, string | number | boolean | null>;

function assertString(value: unknown, name: string): asserts value is string {
	if (typeof value !== 'string') {
		throw new Error(`${name} must be a string`);
	}
}

function assertNonEmptyString(value: string, name: string): void {
	if (value.trim() === '') {
		throw new Error(`${name} must be a non-empty string`);
	}
}

function isValidXmlName(name: string): boolean {
	return /^[A-Za-z_][A-Za-z0-9._-]*$/.test(name);
}

function assertValidXmlName(name: string, paramName: string): void {
	assertString(name, paramName);
	assertNonEmptyString(name, paramName);
	if (!isValidXmlName(name)) {
		throw new Error(`${paramName} is not a valid XML element name`);
	}
}

function assertRows(rows: Row[]): void {
	if (!Array.isArray(rows)) {
		throw new Error('rows must be an array');
	}
	for (let i = 0; i < rows.length; i++) {
		const row = rows[i];
		if (row === null || typeof row !== 'object' || Array.isArray(row)) {
			throw new Error(`rows[${i}] must be an object`);
		}
		for (const key of Object.keys(row)) {
			const v = row[key];
			const t = typeof v;
			if (!(v === null || t === 'string' || t === 'number' || t === 'boolean')) {
				throw new Error(`rows[${i}].${key} has unsupported value type`);
			}
			if (t === 'number' && !Number.isFinite(v as number)) {
				throw new Error(`rows[${i}].${key} must be a finite number`);
			}
		}
	}
}

function escapeCsvField(value: string): string {
	if (/[",\n\r]/.test(value)) {
		return `"${value.replace(/"/g, '""')}"`;
	}
	return value;
}

function parseCsvLine(line: string): string[] {
	const fields: string[] = [];
	let current = '';
	let i = 0;
	let inQuotes = false;

	while (i < line.length) {
		const ch = line[i];
		if (inQuotes) {
			if (ch === '"') {
				if (i + 1 < line.length && line[i + 1] === '"') {
					current += '"';
					i += 2;
				} else {
					inQuotes = false;
					i++;
				}
			} else {
				current += ch;
				i++;
			}
		} else {
			if (ch === ',') {
				fields.push(current);
				current = '';
				i++;
			} else if (ch === '"') {
				if (current.length > 0) {
					throw new Error('Invalid CSV format: quote in unquoted field');
				}
				inQuotes = true;
				i++;
			} else {
				current += ch;
				i++;
			}
		}
	}

	if (inQuotes) {
		throw new Error('Invalid CSV format: unclosed quote');
	}
	fields.push(current);
	return fields;
}

function parseCsvValue(value: string): string | number | boolean | null {
	const trimmed = value.trim();
	if (trimmed === '') return '';
	if (trimmed === 'null') return null;
	if (trimmed === 'true') return true;
	if (trimmed === 'false') return false;
	if (/^-?(?:0|[1-9]\d*)(?:\.\d+)?(?:[eE][+-]?\d+)?$/.test(trimmed)) {
		const n = Number(trimmed);
		if (Number.isFinite(n)) return n;
	}
	return value;
}

function serializePrimitive(value: string | number | boolean | null): string {
	if (value === null) return 'null';
	if (typeof value === 'string') return value;
	return String(value);
}

function escapeXml(text: string): string {
	return text
		.replace(/&/g, '&amp;')
		.replace(/</g, '&lt;')
		.replace(/>/g, '&gt;')
		.replace(/"/g, '&quot;')
		.replace(/'/g, '&apos;');
}

function unescapeXml(text: string): string {
	return text
		.replace(/&lt;/g, '<')
		.replace(/&gt;/g, '>')
		.replace(/&quot;/g, '"')
		.replace(/&apos;/g, "'")
		.replace(/&amp;/g, '&');
}

function stripXmlDeclaration(xml: string): string {
	return xml.replace(/^\s*<\?xml[^>]*\?>\s*/i, '');
}

export function jsonToCsv(rows: Row[]): string {
	assertRows(rows);
	if (rows.length === 0) return '';

	const headers = Array.from(
		rows.reduce((set, row) => {
			for (const k of Object.keys(row)) set.add(k);
			return set;
		}, new Set<string>())
	);

	const headerLine = headers.map(escapeCsvField).join(',');
	const dataLines = rows.map((row) =>
		headers.map((h) => escapeCsvField(serializePrimitive(row[h] ?? null))).join(',')
	);

	return [headerLine, ...dataLines].join('\n');
}

export function csvToJson(csv: string): Row[] {
	assertString(csv, 'csv');
	if (csv.trim() === '') return [];

	const normalized = csv.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
	const lines = normalized.split('\n');
	if (lines.length === 0) return [];

	const headers = parseCsvLine(lines[0]);
	if (headers.length === 0) {
		throw new Error('Invalid CSV: missing header');
	}
	for (const h of headers) {
		if (h.trim() === '') throw new Error('Invalid CSV: empty header name');
	}

	const rows: Row[] = [];
	for (let i = 1; i < lines.length; i++) {
		if (lines[i] === '' && i === lines.length - 1) continue;
		const fields = parseCsvLine(lines[i]);
		if (fields.length !== headers.length) {
			throw new Error(`Invalid CSV: row ${i} has ${fields.length} fields, expected ${headers.length}`);
		}
		const row: Row = {};
		for (let j = 0; j < headers.length; j++) {
			row[headers[j]] = parseCsvValue(fields[j]);
		}
		rows.push(row);
	}
	return rows;
}

export function jsonToXml(rows: Row[], rootElement: string, rowElement: string): string {
	assertRows(rows);
	assertValidXmlName(rootElement, 'rootElement');
	assertValidXmlName(rowElement, 'rowElement');

	const body = rows
		.map((row) => {
			const fields = Object.keys(row)
				.map((k) => {
					if (!isValidXmlName(k)) {
						throw new Error(`Invalid XML field name: ${k}`);
					}
					const v = serializePrimitive(row[k]);
					return `<${k}>${escapeXml(v)}</${k}>`;
				})
				.join('');
			return `<${rowElement}>${fields}</${rowElement}>`;
		})
		.join('');

	return `<${rootElement}>${body}</${rootElement}>`;
}

export function xmlToJson(xml: string, rowElement: string): Row[] {
	assertString(xml, 'xml');
	assertValidXmlName(rowElement, 'rowElement');

	const cleaned = stripXmlDeclaration(xml).trim();
	if (cleaned === '') throw new Error('xml must be a non-empty string');

	const rowRegex = new RegExp(`<${rowElement}>([\\s\\S]*?)<\\/${rowElement}>`, 'g');
	const rows: Row[] = [];
	let rowMatch: RegExpExecArray | null;

	while ((rowMatch = rowRegex.exec(cleaned)) !== null) {
		const rowContent = rowMatch[1];
		const fieldRegex = /<([A-Za-z_][A-Za-z0-9._-]*)>([\s\S]*?)<\/\1>/g;
		const row: Row = {};
		let fieldMatch: RegExpExecArray | null;
		let consumed = '';
		while ((fieldMatch = fieldRegex.exec(rowContent)) !== null) {
			const key = fieldMatch[1];
			const raw = unescapeXml(fieldMatch[2]);
			row[key] = parseCsvValue(raw);
			consumed += fieldMatch[0];
		}
		if (rowContent.replace(/\s/g, '') !== consumed.replace(/\s/g, '')) {
			throw new Error('Invalid XML row structure');
		}
		rows.push(row);
	}

	if (rows.length === 0 && cleaned.includes(`<${rowElement}>`)) {
		throw new Error('Invalid XML format');
	}

	return rows;
}

export function csvToXml(csv: string, rootElement: string, rowElement: string): string {
	return jsonToXml(csvToJson(csv), rootElement, rowElement);
}

export function xmlToCsv(xml: string, rowElement: string): string {
	return jsonToCsv(xmlToJson(xml, rowElement));
}

