import axios from 'axios';

type PrimitiveQueryValue = string | number | boolean;
type HeadersMap = Record<string, string>;

interface ConfigureOptions {
	baseURL: string;
	headers?: HeadersMap;
}

interface PostOptions {
	headers?: HeadersMap;
}

interface ParsedItem {
	id: unknown;
	label: string;
	meta: Record<string, unknown>;
}

let baseURL = '';
const defaultHeaders: HeadersMap = {};

function isRecord(value: unknown): value is Record<string, unknown> {
	return typeof value === 'object' && value !== null;
}

export function configure(options: ConfigureOptions): void {
	baseURL = options.baseURL;
	if (options.headers) {
		Object.assign(defaultHeaders, options.headers);
	}
}

export async function get<T>(path: string, params?: Record<string, unknown>): Promise<T> {
	const response = await axios.get<T>(baseURL + path, {
		params,
		headers: defaultHeaders,
	});
	return response.data;
}

export async function post<T>(path: string, body?: unknown, options?: PostOptions): Promise<T> {
	const response = await axios.post<T>(baseURL + path, body, {
		headers: {
			...defaultHeaders,
			...(options && options.headers),
		},
	});
	return response.data;
}

export function buildQueryString(params: Record<string, PrimitiveQueryValue | null | undefined>): string {
	return Object.entries(params)
		.filter(([, v]) => v !== undefined && v !== null)
		.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
		.join('&');
}

export function parseResponse(raw: unknown): ParsedItem[] {
	if (!isRecord(raw)) {
		return [];
	}
	const data = raw.data;
	if (!isRecord(data)) {
		return [];
	}
	const items = data.items;
	if (!Array.isArray(items)) {
		return [];
	}

	return items.map((item) => {
		let id: unknown;
		let label = 'Unknown';
		let meta: Record<string, unknown> = {};

		if (isRecord(item)) {
			id = item.id;

			const name = item.name;
			const title = item.title;
			const itemMeta = item.meta;

			if (typeof name === 'string' && name.length > 0) {
				label = name;
			} else if (typeof title === 'string' && title.length > 0) {
				label = title;
			}

			if (isRecord(itemMeta)) {
				meta = itemMeta;
			}
		}

		return {
			id,
			label,
			meta,
		};
	});
}

