export function jaroWinkler(s1: string, s2: string): number {
	if (s1 === s2) return 1;

	const len1 = s1.length;
	const len2 = s2.length;

	if (len1 === 0 || len2 === 0) return 0;

	const matchDistance = Math.floor(Math.max(len1, len2) / 2) - 1;

	const s1Matches = new Array<boolean>(len1).fill(false);
	const s2Matches = new Array<boolean>(len2).fill(false);

	let matches = 0;

	for (let i = 0; i < len1; i++) {
		const start = Math.max(0, i - matchDistance);
		const end = Math.min(i + matchDistance + 1, len2);

		for (let j = start; j < end; j++) {
			if (s2Matches[j]) continue;
			if (s1[i] !== s2[j]) continue;
			s1Matches[i] = true;
			s2Matches[j] = true;
			matches++;
			break;
		}
	}

	if (matches === 0) return 0;

	let transpositions = 0;
	let k = 0;

	for (let i = 0; i < len1; i++) {
		if (!s1Matches[i]) continue;
		while (!s2Matches[k]) k++;
		if (s1[i] !== s2[k]) transpositions++;
		k++;
	}

	transpositions /= 2;

	const m = matches;
	const jaro =
		(m / len1 + m / len2 + (m - transpositions) / m) / 3;

	let prefix = 0;
	const maxPrefix = Math.min(4, len1, len2);
	while (prefix < maxPrefix && s1[prefix] === s2[prefix]) {
		prefix++;
	}

	const p = 0.1;
	const jaroWinklerScore = jaro + prefix * p * (1 - jaro);

	return Math.max(0, Math.min(1, jaroWinklerScore));
}

